/* ── Editor text formats ── */
.editor-text-bold {
    font-weight: bold;
}
.editor-text-italic {
    font-style: italic;
}
.editor-text-underline {
    text-decoration: underline;
}

/* ── Editor container variables (derived from global theme) ── */
.editor-container {
    --editor-bg: var(--bg-elevated);
    --editor-surface: var(--bg-secondary);
    --editor-text: var(--text-primary);
    --editor-border: var(--border-light);
    --editor-accent: var(--accent-purple);
}

/* ── Overlay backdrop ── */
.editor-parent-container {
    display: flex;
    justify-content: center;
    align-items: center;
    position: absolute;
    width: 100%;
    height: 100%;
    background-color: var(--bg-overlay);
    backdrop-filter: blur(25px);
    z-index: 130;
}

/* ── Main editor card ── */
.editor-container {
    display: flex;
    flex-direction: column;
    width: 100%;
    max-width: 720px;
    height: 80%;
    min-height: 0;
    overflow: hidden;
    background-color: var(--editor-bg);
    color: var(--editor-text);
    border-radius: 16px;
    padding: 1rem 1.5rem;
    box-shadow: var(--shadow-modal);
}

.editor-mode-shell {
    position: relative;
    display: flex;
    flex-direction: column;
    flex: 1;
    min-height: 0;
    overflow: hidden;
}

/* ── Close button row ── */
.editor-close-bttn-container {
    display: flex;
    width: 100%;
    justify-content: flex-end;
    align-items: center;
}
.editor-close-bttn {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0.4rem;
    border: none;
    background: transparent;
    border-radius: 50%;
    cursor: pointer;
    color: var(--text-muted);
    transition: background-color 0.15s ease, color 0.15s ease, transform 0.15s ease;
}
.editor-close-bttn svg {
    fill: var(--text-muted);
    transition: fill 0.15s ease;
}
.editor-close-bttn:hover {
    background-color: var(--bg-pill);
    color: var(--editor-text);
    transform: scale(1.05);
}
.editor-close-bttn:hover svg {
    fill: var(--editor-text);
}

/* ── Title input ── */
.content-title-input {
    margin: 0.5rem 0;
    border: none;
    border-bottom: 2px solid transparent;
    background-color: transparent;
    font-size: 1.75rem;
    font-weight: 650;
    font-family: var(--font-serif);
    padding: 0.5rem 0.25rem;
    color: var(--editor-text);
    transition: border-color 0.25s ease;
}
.content-title-input::placeholder {
    color: var(--text-muted);
}
.content-title-input:focus {
    outline: none;
    border-bottom-color: var(--editor-accent);
}

/* ── Toolbar (above content) ── */
.toolbar-wrapper {
    display: flex;
    align-items: center;
    border-top: 1px solid var(--editor-border);
    border-bottom: 1px solid var(--editor-border);
    padding: 0.35rem 0;
    margin-bottom: 0;
    position: sticky;
    top: 0;
    z-index: 5;
    background-color: var(--editor-bg);
}
.toolbar {
    display: flex;
    align-items: center;
    gap: 2px;
    width: 100%;
    flex-wrap: wrap;
}
.group {
    display: flex;
    align-items: center;
    gap: 2px;
}
.toolbar-divider {
    width: 1px;
    height: 20px;
    background-color: var(--editor-border);
    margin: 0 6px;
    flex-shrink: 0;
}
.toolbar-bttns {
    display: flex;
    width: fit-content;
    height: fit-content;
    justify-content: center;
    align-items: center;
    padding: 0.4rem;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.15s ease;
    user-select: none;
    color: var(--editor-text);
}
.toolbar-bttns svg {
    fill: var(--editor-text);
    transition: fill 0.15s ease;
}
.toolbar-bttns:hover {
    background-color: var(--bg-pill);
}
.is-active {
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    padding: 0.4rem;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.15s ease;
    user-select: none;
    background-color: color-mix(in srgb, var(--editor-accent) 15%, transparent);
}
.is-active svg {
    fill: var(--editor-accent);
}

/* ── Color pickers ── */
.toolbar-color-picker {
    position: relative;
    display: flex;
    align-items: center;
}
.toolbar-color-trigger {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 0.35rem 0.45rem;
    border-radius: 6px;
    border: none;
    background: transparent;
    cursor: pointer;
    color: var(--editor-text);
    transition: background-color 0.15s ease;
}
.toolbar-color-trigger:hover {
    background-color: var(--bg-pill);
}
.toolbar-color-icon {
    font-weight: 700;
    font-size: 0.9rem;
    line-height: 1;
}
.toolbar-color-swatch {
    width: 16px;
    height: 4px;
    border-radius: 3px;
    border: 1px solid var(--editor-border);
}
.color-popover {
    position: absolute;
    top: calc(100% + 6px);
    left: 0;
    display: grid;
    grid-template-columns: repeat(6, 18px);
    gap: 6px;
    padding: 8px;
    background: var(--editor-bg);
    border: 1px solid var(--editor-border);
    border-radius: 8px;
    box-shadow: var(--shadow-modal);
    z-index: 12;
}
.color-swatch {
    width: 18px;
    height: 18px;
    border-radius: 4px;
    border: 1px solid var(--editor-border);
    cursor: pointer;
    background-color: transparent;
}
.color-swatch.is-default {
    background-image:
        linear-gradient(45deg, rgba(0, 0, 0, 0.15) 25%, transparent 25%),
        linear-gradient(-45deg, rgba(0, 0, 0, 0.15) 25%, transparent 25%),
        linear-gradient(45deg, transparent 75%, rgba(0, 0, 0, 0.15) 75%),
        linear-gradient(-45deg, transparent 75%, rgba(0, 0, 0, 0.15) 75%);
    background-size: 6px 6px;
    background-position: 0 0, 0 3px, 3px -3px, -3px 0px;
}
.color-swatch.is-selected {
    outline: 2px solid var(--editor-accent);
    outline-offset: 1px;
}

/* ── Editor shell (flex-grow, scrollable) ── */
.editor-shell {
    position: relative;
    flex: 1;
    min-height: 0;
    overflow-y: auto;
    overflow-x: auto;
    scrollbar-width: thin;
    scrollbar-color: var(--text-muted) transparent;
}
.editor-shell::-webkit-scrollbar {
    width: 6px;
}
.editor-shell::-webkit-scrollbar-thumb {
    background: var(--text-muted);
    border-radius: 4px;
}
.editor-shell::-webkit-scrollbar-track {
    background-color: transparent;
}

